"use client"

import { useState } from "react"
import { Database, CheckCircle2, XCircle, Terminal, Play, Home, AlertTriangle } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from "@/components/ui/card"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import Link from "next/link"

export default function SetupPage() {
  const [loading, setLoading] = useState(false)
  const [logs, setLogs] = useState<string[]>([])
  const [status, setStatus] = useState<"idle" | "success" | "error">("idle")

  const addLog = (message: string) => {
    setLogs(prev => [...prev, `> ${message}`])
  }

  const handleInit = async () => {
    setLoading(true)
    setStatus("idle")
    setLogs([])
    addLog("Starting database initialization...")

    try {
      addLog("Connecting to /api/init endpoint...")
      const response = await fetch('/api/init')

      const contentType = response.headers.get("content-type");
      let data;

      if (contentType && contentType.indexOf("application/json") !== -1) {
        data = await response.json();
      } else {
        const text = await response.text();
        const statusText = response.statusText || "Unknown Error";
        let errorMessage = `Server returned ${response.status} ${statusText} (Non-JSON response)`;

        // Try to extract title from HTML error page
        const titleMatch = text.match(/<title>(.*?)<\/title>/i);
        if (titleMatch && titleMatch[1]) {
          errorMessage += `: ${titleMatch[1]}`;
        }

        addLog(`❌ ${errorMessage}`);
        console.error("Non-JSON Response Body:", text);
        throw new Error(errorMessage);
      }

      if (response.ok && data.success) {
        addLog("✅ Success!")
        addLog(data.message)
        setStatus("success")
      } else {
        addLog("❌ Failed.")
        addLog(`Error: ${data.error || "Unknown error"}`)
        setStatus("error")
      }
    } catch (error: any) {
      addLog("❌ Network/System Error.")
      addLog(error.message)
      setStatus("error")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <Card className="w-full max-w-2xl shadow-xl border-slate-200">
        <CardHeader className="bg-white border-b pb-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 bg-blue-600 rounded-lg flex items-center justify-center">
                <Database className="h-6 w-6 text-white" />
              </div>
              <div>
                <CardTitle className="text-xl">System Setup & Repair</CardTitle>
                <CardDescription>Initialize Cloudflare D1 Database Tables</CardDescription>
              </div>
            </div>
            <Link href="/">
              <Button variant="ghost" size="sm">
                <Home className="h-4 w-4 mr-2" />
                Back Home
              </Button>
            </Link>
          </div>
        </CardHeader>

        <CardContent className="space-y-6 pt-6">
          <Alert className="bg-blue-50 border-blue-200 text-blue-800">
            <AlertTriangle className="h-4 w-4 text-blue-600" />
            <AlertTitle>First Time Setup?</AlertTitle>
            <AlertDescription>
              If you are seeing <strong>500 Internal Server Errors</strong> on the dashboard, it likely means your database tables haven't been created yet. Run the initialization below to fix this.
            </AlertDescription>
          </Alert>

          <div className="grid gap-4">
            <h3 className="font-medium text-sm text-slate-500 uppercase tracking-wider">Actions</h3>
            <div className="flex gap-4">
              <Button 
                onClick={handleInit} 
                disabled={loading} 
                className="w-full h-12 text-lg bg-blue-600 hover:bg-blue-700"
              >
                {loading ? (
                  <span className="flex items-center gap-2">Creating Tables...</span>
                ) : (
                  <span className="flex items-center gap-2"><Play className="h-5 w-5" /> Initialize Database Tables</span>
                )}
              </Button>
            </div>
          </div>

          <div className="space-y-2">
            <h3 className="font-medium text-sm text-slate-500 uppercase tracking-wider flex items-center gap-2">
              <Terminal className="h-4 w-4" /> Console Log
            </h3>
            <div className="bg-slate-900 text-green-400 p-4 rounded-lg font-mono text-sm min-h-[160px] max-h-[300px] overflow-y-auto">
              {logs.length === 0 ? (
                <span className="opacity-50 text-slate-500">Waiting for command...</span>
              ) : (
                logs.map((log, i) => (
                  <div key={i} className="mb-1 border-b border-slate-800/50 pb-1 last:border-0 last:pb-0">
                    {log}
                  </div>
                ))
              )}
            </div>
          </div>

          {status === "success" && (
            <div className="p-4 bg-green-50 border border-green-200 rounded-lg flex items-center gap-3 text-green-800 animate-in fade-in slide-in-from-top-2">
              <CheckCircle2 className="h-6 w-6 text-green-600" />
              <div>
                <p className="font-semibold">Database Configured Successfully!</p>
                <p className="text-sm">You can now access the Admin Panel.</p>
              </div>
              <Button asChild className="ml-auto bg-green-600 hover:bg-green-700 text-white">
                <Link href="/admin">Go to Admin</Link>
              </Button>
            </div>
          )}

          {status === "error" && (
            <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-center gap-3 text-red-800 animate-in fade-in slide-in-from-top-2">
              <XCircle className="h-6 w-6 text-red-600" />
              <div>
                <p className="font-semibold">Initialization Failed</p>
                <p className="text-sm">Check the logs above. Ensure <code>DB</code> is bound in Cloudflare Pages settings.</p>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

import { getRequestContext } from '@cloudflare/next-on-pages'
import { NextResponse } from 'next/server'

// Remove explicit edge runtime to fallback to Node.js if needed, or let adapter handle it.
// export const runtime = 'edge' 

export async function GET() {
  try {
    // Safely attempt to get context, but don't crash if it fails
    let env;
    try {
      const ctx = getRequestContext();
      env = ctx.env;
    } catch (e) {
      console.warn("[v0] getRequestContext failed (likely running in standard Node env):", e);
    }

    // Check if DB binding exists
    if (!env || !env.DB) {
      console.error("[v0] Database binding 'DB' not found in environment.")
      return NextResponse.json({ 
        success: false, 
        error: "Database binding 'DB' not found. Please ensure D1 is bound in Cloudflare Pages settings or wrangler.toml with variable name 'DB'." 
      }, { status: 500 })
    }

    // SQL Schema - Using CREATE TABLE IF NOT EXISTS to be safe to run multiple times
    const schemaQueries = [
      `CREATE TABLE IF NOT EXISTS users (
        uid TEXT PRIMARY KEY,
        email TEXT,
        displayName TEXT,
        role TEXT DEFAULT 'user',
        phone TEXT,
        address TEXT,
        city TEXT,
        country TEXT,
        createdAt INTEGER,
        updatedAt INTEGER
      )`,
      `CREATE TABLE IF NOT EXISTS categories (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        slug TEXT,
        description TEXT,
        createdAt INTEGER
      )`,
      `CREATE TABLE IF NOT EXISTS products (
        id TEXT PRIMARY KEY,
        title TEXT NOT NULL,
        description TEXT,
        price REAL NOT NULL,
        discountPrice REAL,
        category TEXT,
        tags TEXT,
        imageUrl TEXT,
        downloadUrl TEXT,
        isActive INTEGER DEFAULT 1,
        salesCount INTEGER DEFAULT 0,
        pageCode TEXT,
        createdBy TEXT,
        createdAt INTEGER,
        updatedAt INTEGER
      )`,
      `CREATE TABLE IF NOT EXISTS orders (
        id TEXT PRIMARY KEY,
        userId TEXT NOT NULL,
        items TEXT,
        totalAmount REAL NOT NULL,
        status TEXT DEFAULT 'pending',
        paymentId TEXT,
        createdAt INTEGER,
        updatedAt INTEGER
      )`,
      // Indexes
      `CREATE INDEX IF NOT EXISTS idx_products_category ON products(category)`,
      `CREATE INDEX IF NOT EXISTS idx_users_email ON users(email)`,
      `CREATE INDEX IF NOT EXISTS idx_orders_user ON orders(userId)`
    ];

    // Execute schema creation one by one
    for (const query of schemaQueries) {
      try {
        await env.DB.prepare(query).run();
      } catch (e: any) {
        console.error(`[v0] Failed to run query: ${query.substring(0, 50)}...`, e);
        throw new Error(`Database error on schema creation: ${e.message}`);
      }
    }

    // Seed Default Categories (Only if empty)
    try {
      const countResult: any = await env.DB.prepare("SELECT count(*) as count FROM categories").first();

      if (countResult && countResult.count === 0) {
        const now = Date.now();
        await env.DB.batch([
          env.DB.prepare("INSERT INTO categories (id, name, slug, description, createdAt) VALUES (?, ?, ?, ?, ?)").bind(crypto.randomUUID(), "Software", "software", "Premium software tools and applications", now),
          env.DB.prepare("INSERT INTO categories (id, name, slug, description, createdAt) VALUES (?, ?, ?, ?, ?)").bind(crypto.randomUUID(), "Templates", "templates", "Ready-to-use project templates", now),
          env.DB.prepare("INSERT INTO categories (id, name, slug, description, createdAt) VALUES (?, ?, ?, ?, ?)").bind(crypto.randomUUID(), "Courses", "courses", "Educational content and tutorials", now)
        ]);
        console.log("[v0] Default categories seeded.");
      }
    } catch (e: any) {
      // Don't fail the whole request if seeding fails, just log it
      console.warn("[v0] Seeding warning (non-critical):", e.message);
    }

    return NextResponse.json({ 
      success: true, 
      message: "Database successfully initialized! Tables created." 
    })

  } catch (e: any) {
    console.error("[v0] DB Init Critical Error:", e)
    return NextResponse.json({ 
      success: false, 
      error: e.message || "Failed to initialize database" 
    }, { status: 500 })
  }
}
